package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions/create")public class AdmissionCreateServlet extends HttpServlet{private final AdmissionService service;public AdmissionCreateServlet(){this(new AdmissionServiceImpl());}public AdmissionCreateServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AdmissionForm f=new AdmissionForm();f.setAppointmentId(AdmissionRequest.id(q.getParameter("appointmentId")));show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AdmissionForm f=AdmissionRequest.admission(q);ServiceResult<Long>x=service.admitPatient(f,AdmissionRequest.audit(q),AdmissionRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admissions/view?id="+x.getData());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,AdmissionForm f)throws ServletException,IOException{q.setAttribute("admissionForm",f);q.getRequestDispatcher("/WEB-INF/views/admissions/form.jsp").forward(q,r);}}
